  if (!session) {
    return null;
  }
  const user = db.users.find((entry) => entry.id === session.userId);
  if (!user) {
    return null;
  }
  return {
    id: user.id,
    name: user.name,
    role: user.role
  };
}

function getCurrentAuthContext(req, db) {
