      };

      await mutateDb((latestDb) => {
        const latestProject = ensureProject(latestDb, projectId);
        if (!latestProject) {
          return;
        }
        latestDb.assets.push(asset);
        if (versionLabel === 'v1') {
          latestProject.status = 'in_review';
        }
        if (versionLabel === 'v2') {
          latestProject.status = 'review_updated';
        }
        logAudit(latestDb, {
