    const voiceNotesMatch = pathname.match(/^\/api\/projects\/([a-f0-9-]+)\/voice-notes$/i);
    if (voiceNotesMatch) {
      const projectId = voiceNotesMatch[1];
      const db = await readDb();
      const currentUser = getCurrentUserFromDb(req, db);
      if (!currentUser) {
