      }

      const projectInputs = db.briefInputs
        .filter((item) => item.projectId === projectId)
        .sort((a, b) => a.createdAt.localeCompare(b.createdAt));

      const mergedText = [
        ...projectInputs.map((item) => `[${item.inputType}] ${item.content}`),
