            sourceCommentId: closestCommentIdByTimestamp(sourceComments, item.timestampSec)
          }));
          mode = 'openai';
        } else {
          providerError = 'openai_shape_validation_failed';
        }
      } else {
        providerError = modelResult.error;
      }

      const generated = await mutateDb((mutableDb) => {
