  if (!OPENAI_API_KEY) {
    return { ok: false, error: 'missing_api_key' };
  }

  const start = Date.now();
  try {
    const response = await fetch('https://api.openai.com/v1/responses', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${OPENAI_API_KEY}`
